"use client";

import { createContext, useContext, useEffect, useState, ReactNode } from "react";

type Role = "user" | "admin" | null;

interface AuthContextValue {
  role: Role;
  loginAsUser: () => void;
  loginAsAdmin: () => void;
  logout: () => void;
}

const AuthContext = createContext<AuthContextValue | undefined>(undefined);

const STORAGE_KEY = "aurora_role";

export function AuthProvider({ children }: { children: ReactNode }) {
  const [role, setRole] = useState<Role>(null);

  useEffect(() => {
    if (typeof window === "undefined") return;
    const stored = window.localStorage.getItem(STORAGE_KEY) as Role | null;
    if (stored === "user" || stored === "admin") {
      setRole(stored);
    }
  }, []);

  const setAndPersist = (next: Role) => {
    setRole(next);
    if (typeof window === "undefined") return;
    if (next) {
      window.localStorage.setItem(STORAGE_KEY, next);
    } else {
      window.localStorage.removeItem(STORAGE_KEY);
    }
  };

  const loginAsUser = () => setAndPersist("user");
  const loginAsAdmin = () => setAndPersist("admin");
  const logout = () => setAndPersist(null);

  return (
    <AuthContext.Provider value={{ role, loginAsUser, loginAsAdmin, logout }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const ctx = useContext(AuthContext);
  if (!ctx) {
    throw new Error("useAuth must be used within <AuthProvider>");
  }
  return ctx;
}

